solutions.javascript:
// Solution
const express = require('express');
const app = express();
app.get('/users/:id', (req, res) => {
  const id = req.params.id;
  if (!/^[0-9]+$/.test(id)) {
    res.status(404).json({ error: 'User not found' });
  } else {
    res.json({ name: 'John Doe', email: 'john@example.com' });
  }
});
